/* SapReturnPreOrdersBatchMapper.xml savePreOrder */
UPDATE TORDER_INFO_PREORDERS
   SET SAPTRANSYN = CASE WHEN #{saptransfailyn}='Y' THEN 'N' ELSE 'Y' END
     , SAPTRANSFAILYN = #{saptransfailyn}
     , UPDATEDATE = #{interfaceDate}
     , UPDATEURKEY = #{interfaceUrkey}
 WHERE OWKEY  = #{owkey} 
   AND PREKEY = #{prekey} 
   AND ORG_CUSTOMERORDERKEY = #{orgCustomerorderkey} 
   AND ORG_CUSTOMERORDERDTKEY = #{orgCustomerorderdtkey}
